import sys

def generate_repunits(limit):
    repunits = set()
    length = 1
    while True:
        repunit = int('1' * length)
        if repunit > limit:
            break
        repunits.add(repunit)
        length += 1
    return repunits

def main():
    N = int(sys.stdin.readline())
    max_repunit_length = 20  # Sufficiently large to cover up to N=333
    repunits = set()
    for length in range(1, max_repunit_length + 1):
        repunit = int('1' * length)
        repunits.add(repunit)

    sums = set()
    repunits = sorted(repunits)
    for i in range(len(repunits)):
        for j in range(i, len(repunits)):
            for k in range(j, len(repunits)):
                s = repunits[i] + repunits[j] + repunits[k]
                sums.add(s)

    sorted_sums = sorted(sums)
    print(sorted_sums[N - 1])

if __name__ == "__main__":
    main()
